#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

inline double randu_gpu(__global int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

inline double randn_gpu(__global int *seed, int index) {
    double u = randu_gpu(seed, index);
    double v = randu_gpu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

inline int findIndex_gpu(__global double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) return lengthCDF - 1;
    return index;
}

__kernel void likelihood_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *xj,
    __global double *yj,
    __global double *CDF,
    __global int *ind,
    __global int *objxy,
    __global double *likelihood,
    __global uchar *I,
    __global double *u,
    __global double *weights,
    int Nparticles,
    int countOnes,
    int max_size,
    int k,
    int IszY,
    int Nfr,
    __global int *seed,
    __global double *partial_sums,
    __local double *buffer)
{
    (void)CDF;
    (void)u;
    (void)buffer;

    int i = get_global_id(0);
    if (i >= Nparticles) return;

    arrayX[i] = xj[i] + 1.0 + 5.0 * randn_gpu(seed, i);
    arrayY[i] = yj[i] - 2.0 + 2.0 * randn_gpu(seed, i);

    double lsum = 0.0;
    int base = i * countOnes;

    for (int y = 0; y < countOnes; y++) {
        int indX = (int)(arrayX[i]) + objxy[y * 2 + 1];
        int indY = (int)(arrayY[i]) + objxy[y * 2];
        int idx = indX * IszY * Nfr + indY * Nfr + k;
        if (idx < 0) idx = -idx;
        if (idx >= max_size) idx = 0;
        ind[base + y] = idx;

        double v = (double)I[idx];
        double d1 = v - 100.0;
        double d2 = v - 228.0;
        lsum += (d1 * d1 - d2 * d2) / 50.0;
    }

    lsum /= (double)countOnes;
    likelihood[i] = lsum;
    weights[i] = weights[i] * exp(lsum);
    partial_sums[i] = weights[i];
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    int gid = get_global_id(0);
    if (gid != 0) return;

    double s = 0.0;
    for (int i = 0; i < Nparticles; i++) s += partial_sums[i];
    partial_sums[0] = s;
}

__kernel void normalize_weights_kernel(
    __global double *weights,
    int Nparticles,
    __global double *partial_sums,
    __global double *CDF,
    __global double *u,
    __global int *seed)
{
    int gid = get_global_id(0);
    if (gid != 0) return;

    double sumWeights = partial_sums[0];
    if (sumWeights == 0.0) sumWeights = 1.0;

    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    if (Nparticles > 0) {
        CDF[0] = weights[0];
        for (int i = 1; i < Nparticles; i++) {
            CDF[i] = CDF[i - 1] + weights[i];
        }
    }

    double u1 = (1.0 / (double)Nparticles) * randu_gpu(seed, 0);
    for (int i = 0; i < Nparticles; i++) {
        u[i] = u1 + ((double)i / (double)Nparticles);
    }
}

__kernel void find_index_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *CDF,
    __global double *u,
    __global double *xj,
    __global double *yj,
    __global double *weights,
    int Nparticles)
{
    int j = get_global_id(0);
    if (j >= Nparticles) return;

    int i = findIndex_gpu(CDF, Nparticles, u[j]);
    if (i < 0) i = Nparticles - 1;

    xj[j] = arrayX[i];
    yj[j] = arrayY[i];
    weights[j] = 1.0 / (double)Nparticles;
}

